const item = $input.first().json;
const body = item.body || item;

// Build dedup fingerprint from normalized title + asset + category
const normalizeTitle = t => (t||'').toLowerCase().replace(/[^a-z0-9]/g,' ').replace(/\s+/g,' ').trim();
const cweId = body.cwe_id || 'unknown';
const assetId = body.asset_id || 'unknown';
const titleNorm = normalizeTitle(body.title);

// Simple hash substitute using string components
const fingerprint = btoa(encodeURIComponent(`${titleNorm}|${assetId}|${cweId}`)).substring(0, 64);

// Category from CWE or source
const cweToCategory = {
  'CWE-89':'injection','CWE-79':'xss','CWE-352':'csrf','CWE-918':'ssrf',
  'CWE-611':'xxe','CWE-22':'path_traversal','CWE-693':'config','CWE-319':'crypto',
  'CWE-326':'crypto','CWE-200':'exposure','CWE-1021':'config','CWE-639':'access_control'
};
const category = cweToCategory[cweId] || 'other';

return [{ json: {
  raw_finding_id: body.raw_finding_id,
  engagement_id: body.engagement_id,
  asset_id: body.asset_id,
  title: body.title,
  severity: body.raw_severity || 'medium',
  cwe_id: cweId === 'unknown' ? null : cweId,
  owasp_category: body.owasp_category || null,
  category,
  raw_evidence: body.raw_evidence || '',
  dedup_fingerprint: fingerprint,
  source_tool: body.source_tool
} }];

const fp = $('Build Dedup Fingerprint').first().json;
const priorCount = parseInt($('Check Cross-Engagement Recurrence').first().json.prior_count || 0);
const isRecurring = priorCount > 0;
return [{ json: { ...fp, is_recurring: isRecurring, recurrence_count: priorCount } }];

